import { Box, Container, Divider, Grid, makeStyles, Paper, Typography } from '@material-ui/core'
import axios from 'axios'
import React, { useEffect, useState } from 'react'
import { useParams } from 'react-router-dom'

const useStyle = makeStyles(theme => {
    return {
        activity: {
            padding: theme.spacing(2),
            width: '100%'
        }
    }
})

function StudentActivity() {
    const classes = useStyle()

    const [post, setPost] = useState({});
    
    const  {id}  = useParams();
    const getPost = () => {
        const sendData = {
          updateID: id
        };
    
    
        axios.post('https://ursacapi.000webhostapp.com/api/getPostID.php', JSON.stringify(sendData))
          .then(response => {
            if (response.data == 0) {
              console.log('post ID not found');
            } else {
              setPost(response.data[0]);
            }
          })
      }

      useEffect(() => {
        getPost();
      }, []);

    return (
        <Box>
            <Container>
                <Grid container>
                    <Grid item>
                        <Paper className={classes.activity} elevation={0} square={true} variant='outlined' >
                            <Typography variant='h4' >
                                {post.title}
                            </Typography>
                            <Typography variant='caption' >
                                Rommel Bonus / Sept. 9
                            </Typography>
                            <Typography variant='body1' >
                                100 points
                            </Typography>
                            <Divider />

                            <Typography variant='body2' >
                                {post.body}

                            </Typography>
                            <Divider />
                            Class Comment
                        </Paper>
                    </Grid>

                </Grid>

            </Container>
        </Box>
    )
}

export default StudentActivity
